import Foundation

struct PremadeTexts {

    // MARK: - Accented Dictionary

    private static let _accentedDict: [String: [String]] = {
        guard let url = Bundle.main.url(forResource: "accented_dictionary", withExtension: "json"),
              let data = try? Data(contentsOf: url),
              let dict = try? JSONDecoder().decode([String: [String]].self, from: data) else {
            return [:]
        }
        return dict
    }()

    static func accentedWords(for character: Character) -> [String] {
        _accentedDict[String(character).lowercased()] ?? []
    }

    // MARK: - Script Texts

    static let arabicVocalization = """
 لعَيْنَيْكِ ما يَلقَى الفُؤادُ وَمَا لَقي وللحُبّ ما لم يَبقَ منّي وما بَقي وَما كنتُ ممّنْ يَدْخُلُ العِشْقُ قلبَه وَلكِنّ مَن يُبصِرْ جفونَكِ يَعشَقِ وَبينَ الرّضَى وَالسُّخطِ وَالقُرْبِ وَالنَّوَى مَجَالٌ لِدَمْعِ المُقْلَةِ المُتَرَقرِقِ وَأحلى الهَوَى ما شكّ في الوَصْلِ رَبُّهُ وَفي الهجرِ فهوَ الدّهرَ يَرْجو وَيَتّقي وَغضْبَى من الإدلالِ سكرَى من الصّبى شَفَعْتُ إلَيها مِنْ شَبَابي برَيِّقِ وَأشنَبَ مَعْسُولِ الثّنِيّاتِ وَاضِحٍ سَتَرْتُ فَمي عَنهُ فَقَبّلَ مَفْرِقي وَأجيادِ غِزْلانٍ كجيدِكِ زُرْنَني فَلَمْ أتَبَيّنْ عاطِلاً مِنْ مُطَوَّقِ وَما كلّ مَن يهوَى يَعِفّ إذا خَلا عَفَافي وَيُرْضي الحِبّ وَالخَيلُ تلتقي سَقَى الله أيّامَ الصّبَى ما يَسُرّهَا وَيَفْعَلُ فِعْلَ البَابِليّ المُعَتَّقِ إذا ما لَبِسْتَ الدّهْرَ مُستَمتِعاً بِهِ تَخَرّقْتَ وَالمَلْبُوسُ لم يَتَخَرّقِ وَلم أرَ كالألحَاظِ يَوْمَ رَحِيلِهِمْ بَعثنَ بكلّ القتل من كلّ مُشفِقِ أدَرْنَ عُيُوناً حائِراتٍ كأنّهَا مُرَكَّبَةٌ أحْداقُهَا فَوْقَ زِئْبِقِ عَشِيّةَ يَعْدُونَا عَنِ النّظَرِ البُكَا وَعن لذّةِ التّوْديعِ خوْفُ التّفَرّقِ نُوَدّعُهُمْ وَالبَيْنُ فينَا كأنّهُ قَنَا ابنِ أبي الهَيْجاءِ في قلبِ فَيلَقِ قَوَاضٍ مَوَاضٍ نَسجُ داوُدَ عندَها إذا وَقَعَتْ فيهِ كنَسْجِ الخدَرْنَقِ هَوَادٍ لأمْلاكِ الجُيُوشِ كأنّهَا تَخَيَّرُ أرْوَاحَ الكُمَاةِ وتَنْتَقي تَقُدّ عَلَيْهِمْ كلَّ دِرْعٍ وَجَوْشنٍ وَتَفري إليهِمْ كلَّ سورٍ وَخَندَقِ يُغِيرُ بهَا بَينَ اللُّقَانِ وَوَاسِطٍ وَيَرْكُزُهَا بَينَ الفُراتِ وَجِلّقِ وَيَرْجِعُهَا حُمْراً كأنّ صَحيحَهَا يُبَكّي دَماً مِنْ رَحمَةِ المُتَدَقِّقِ فَلا تُبْلِغَاهُ ما أقُولُ فإنّهُ شُجاعٌ متى يُذكَرْ لهُ الطّعنُ يَشْتَقِ ضَرُوبٌ بأطرافِ السّيُوفِ بَنانُهُ لَعُوبٌ بأطْرافِ الكَلامِ المُشَقَّقِ كسَائِلِهِ مَنْ يَسألُ الغَيثَ قَطرَةً كعاذِلِهِ مَنْ قالَ للفَلَكِ ارْفُقِ لقد جُدْتَ حتى جُدْتَ في كلّ مِلّةٍ وحتى أتاكَ الحَمدُ من كلّ مَنطِقِ رَأى مَلِكُ الرّومِ ارْتياحَكَ للنّدَى فَقامَ مَقَامَ المُجْتَدي المُتَمَلِّقِ وخَلّى الرّماحَ السّمْهَرِيّةَ صاغِراً لأدْرَبَ منهُ بالطّعانِ وَأحْذَقِ وكاتَبَ مِن أرْضٍ بَعيدٍ مَرامُهَا قَريبٍ على خَيْلٍ حَوَالَيكَ سُبّقِ وَقَد سارَ في مَسراكَ مِنها رَسُولُهُ فَمَا سارَ إلاّ فَوْقَ هامٍ مُفَلَّقِ فَلَمّا دَنَا أخْفَى عَلَيْهِ مَكانَهُ شُعَاعُ الحَديدِ البارِقِ المُتَألّقِ وَأقْبَلَ يَمشِي في البِساطِ فَما درَى إلى البَحرِ يَسعى أمْ إلى البَدْرِ يرْتَقي ولَمْ يَثْنِكَ الأعْداءُ عَنْ مُهَجاتِهمْ بمِثْلِ خُضُوعٍ في كَلامٍ مُنَمَّقِ وَكُنْتَ إذا كاتَبْتَهُ قَبْلَ هذِهِ كَتَبْتَ إليْهِ في قَذالِ الدّمُسْتُقِ فإنْ تُعْطِهِ مِنْكَ الأمانَ فَسائِلٌ وَإنْ تُعْطِهِ حَدّ الحُسامِ فأخلِقِ وَهَلْ تَرَكَ البِيضُ الصّوارِمُ منهُمُ حَبِيساً لِفَادٍ أوْ رَقيقاً لمُعْتِقِ لَقَد وَرَدوا وِرْدَ القَطَا شَفَرَاتِهَا وَمَرّوا عَلَيْها رَزْدَقاً بعدَ رَزْدَقِ بَلَغْتُ بسَيْفِ الدّوْلَةِ النّورِ رُتْبَةً أنَرْتُ بها مَا بَينَ غَرْبٍ وَمَشرِقِ إذا شاءَ أنْ يَلْهُو بلِحيَةِ أحْمَقٍ أراهُ غُبَاري ثمّ قالَ لَهُ الحَقِ وَما كمَدُ الحُسّادِ شيءٌ قَصَدْتُهُ وَلكِنّهُ مَن يَزْحَمِ البَحرَ يَغرَقِ وَيَمْتَحِنُ النّاسَ الأميرُ برَأيِهِ وَيُغضِي على عِلْمٍ بكُلّ مُمَخْرِقِ وَإطراقُ طَرْفِ العَينِ لَيسَ بنافعٍ إذا كانَ طَرْفُ القلبِ ليسَ بمطرِقِ فيا أيّها المَطلوبُ جاوِرْهُ تَمْتَنِعْ وَيا أيّهَا المَحْرُومُ يَمِّمْهُ تُرْزَقِ وَيا أجبنَ الفُرْسانِ صاحِبْهُ تجترىءْ ويا أشجَعَ الشجعانِ فارِقْهُ تَفْرَقِ إذا سَعَتِ الأعْداءُ في كَيْدِ مجْدِهِ سعى جَدُّهُ في كيدهم سعيَ مُحْنَقِ وَما ينصُرُ الفضْلُ المُبينُ على العدَى إذا لم يكُنْ فضْلَ السّعيدِ المُوَفَّقِ الحُبُّ ما مَنَعَ الكَلامَ الألْسُنَا الحُبُّ ما مَنَعَ الكَلامَ الألْسُنَا وألَذُّ شَكْوَى عاشِقٍ ما أعْلَنَا ليتَ الحَبيبَ الهاجري هَجْرَ الكَرَى من غيرِ جُرْمٍ واصِلي صِلَةَ الضّنى بِتْنَا ولَوْ حَلّيْتَنا لمْ تَدْرِ مَا ألْوانُنَا ممّا اسْتُفِعْنَ تَلَوُّنَا وتَوَقّدَتْ أنْفاسُنا حتى لَقَدْ أشْفَقْتُ تَحْتَرِقُ العَواذِلُ بَينَنَا أفْدي المُوَدِّعَةَ التي أتْبَعْتُهَا نَظَراً فُرادَى بَينَ زَفْراتٍ ثُنَا أنْكَرْتُ طارِقَةَ الحَوادِثِ مَرّةً ثُمّ اعْتَرَفتُ بها فصارَتْ دَيْدَنَا وقَطَعْتُ في الدّنْيا الفَلا ورَكائِبي فيها وَوَقْتيّ الضّحَى والمَوْهِنَا فوَقَفْتُ منها حيثُ أوْقَفَني النّدَى وبَلَغْتُ من بَدْرِ بنِ عَمّارَ المُنى لأبي الحُسَينِ جَداً يَضيقُ وِعاؤهُ عَنْهُ ولَوْ كانَ الوِعاءُ الأزْمُنَا وشَجاعَةٌ أغْناهُ عَنْها ذِكْرُها ونَهَى الجَبَانَ حَديثُها أن يجُبنَا نِيطَتْ حَمائِلُهُ بعاتِقِ مِحْرَبٍ ما كَرّ قَطُّ وهَلْ يكُرُّ وما کنْثَنَى فكأنّهُ والطّعْنُ منْ قُدّامِهِ مُتَخَوِّفٌ مِنْ خَلفِهِ أنْ يُطْعَنَا نَفَتِ التّوَهُّمَ عَنْهُ حِدّةُ ذِهْنِهِ فقَضَى على غَيبِ الأمورِ تَيَقُّنَا يَتَفَزّعُ الجَبّارُ مِنْ بَغَتاتِهِ فَيَظَلّ في خَلَواتِهِ مُتَكَفِّنَا أمْضَى إرادَتَهُ فَسَوْفَ لَهُ قَدٌ واستَقرَبَ الأقصَى فَثَمّ لهُ هُنَا يَجِدُ الحَديدَ على بَضاضةِ جِلْدِهِ ثَوْباً أخَفَّ مِنَ الحَريرِ وألْيَنا وأمَرُّ مِنْ فَقْدِ الأحِبّةِ عِندَهُ فَقْدُ السّيُوفِ الفاقِداتِ الأجْفُنَا لا يَستَكِنّ الرّعبُ بَينَ ضُلُوعِهِ يَوْماً ولا الإحسانُ أنْ لا يُحْسِنَا مُسْتَنْبِطٌ من عِلْمِهِ ما في غَدٍ فكأنّ ما سيَكونُ فيهِ دُوِّنَا تَتَقاصَرُ الأفهامُ عَنْ إدْراكِهِ مِثْلَ الذي الأفْلاكُ فيهِ والدُّنَى مَنْ لَيسَ مِنْ قَتْلاهُ من طُلَقائِهِ مَنْ لَيسَ ممّنْ دانَ ممّنْ حُيِّنَا لمّا قَفَلْتَ مِنَ السّواحِلِ نَحْوَنَا قَفَلَتْ إلَيْها وَحْشَةٌ من عِندِنا أرِجَ الطّريقُ فَما مَرَرْتَ بمَوْضِعٍ إلاّ أقامَ بهِ الشّذا مُسْتَوْطِنَا لَوْ تَعْقِلُ الشّجَرُ التي قابَلْتَها مَدّتْ مُحَيّيَةً إلَيكَ الأغْصُنَا سَلَكَتْ تَماثيلَ القِبابِ الجِنُّ من شَوْقٍ بها فأدَرْنَ فيكَ الأعْيُنَا طَرِبَتْ مَراكِبُنَا فَخِلْنا أنّها لَوْلا حَيَاءٌ عاقَها رَقَصَتْ بنا أقْبَلْتَ تَبْسِمُ والجِيادُ عَوَابِسٌ يَخْبُبْنَ بالحَلَقِ المُضاعَفِ والقَنَا عَقَدَتْ سَنابِكُها عَلَيْها عِثْيَراً لوْ تَبتَغي عَنَقاً عَلَيْهِ لأمْكَنَا والأمْرُ أمرُكَ والقُلُوبُ خوافِقٌ في مَوْقِفٍ بَينَ المَنيّةِ والمُنى فعَجِبْتُ حتى ما عَجبتُ من الظُّبَى ورأيْتُ حتى ما رأيْتُ منَ السّنى إنّي أراكَ منَ المَكارِمِ عَسكَراً في عَسكَرٍ ومنَ المَعالي مَعْدِنَا فَطَنَ الفُؤادُ لِما أتَيْتُ على النّوَى ولِمَا تَرَكْتُ مَخافَةً أنْ تَفْطُنَا أضحَى فِراقُكَ لي عَلَيْهِ عُقُوبَةً لَيسَ الذي قاسَيْتُ منْهُ هَيّنَا فاغْفِرْ فِدًى لكَ واحبُني مِنْ بعدها لِتَخُصّني بِعَطِيّةٍ مِنْها أنَا وَانْهَ المُشيرَ عَلَيكَ فيّ بِضِلّةٍ فالحُرُّ مُمْتَحَنٌ بأوْلادِ الزّنَى وإذا الفتى طَرَحَ الكَلامَ مُعَرِّضاً في مجْلِسٍ أخذَ الكَلامَ اللَّذْ عَنى ومَكايِدُ السّفَهاءِ واقِعَةٌ بهِمْ وعَداوَةُ الشّعَراءِ بِئْسَ المُقْتَنى لُعِنَتْ مُقارَنَةُ اللّئيمِ فإنّهَا ضَيْفٌ يَجرُّ منَ النّدامةِ ضَيْفَنَا غَضَبُ الحَسُودِ إذا لَقيتُكَ راضِياً رُزْءٌ أخَفُّ عليّ مِنْ أنْ يُوزَنَا أمسَى الذي أمْسَى برَبّكَ كافِراً مِنْ غَيرِنا مَعَنا بفَضْلِكَ مُؤمِنَا خَلَتِ البِلادُ منَ الغَزالَةِ لَيْلَها فأعاضَهاكَ الله كَيْ لا تَحْزَنَا دَمْعٌ جرَى فقضَى في الرَّبْعِ ما وجَبَا دَمْعٌ جرَى فقضَى في الرَّبْعِ ما وجَبَا لأهلِهِ وشَفَى أنّى ولا كَرَبَا عُجْنا فأذهَبَ ما أبْقَى الفِراقُ لَنا منَ العُقُولِ وما رَدّ الذي ذَهَبَا سَقَيْتُهُ عَبَراتٍ ظَنّهَا مَطَراً سَوائِلاً من جُفُونٍ ظَنّها سُحُبَا دارُ المُلِمِّ لها طَيفٌ تَهَدّدَني لَيلاً فَما صَدَقتْ عَيني ولا كَذَبَا أنْأيْتُهُ فَدَنا، أدْنَيْتُهُ فنَأى، جَمّشْتُهُ فَنَبَا، قَبّلْتُهُ فأبَى هامَ الفُؤادُ بأعرابِيّةٍ سَكَنَتْ بَيْتاً من القلبِ لم تَمدُدْ له طُنُبَا مَظْلُومَةُ القَدّ في تَشْبيهِهِ غُصُناً مَظلُومَةُ الرّيقِ في تَشبيهِهِ ضَرَبَا بَيضاءُ تُطمِعُ في ما تحتَ حُلّتِها وعَزّ ذلكَ مَطْلُوباً إذا طُلِبَا كأنّها الشّمسُ يُعْيي كَفَّ قابضِهِ شُعاعُها ويَراهُ الطّرْفُ مُقْتَرِبَا مَرّتْ بنا بَينَ تِرْبَيْها فقُلتُ لَها من أينَ جانَسَ هذا الشّادِنُ العَرَبَا فکستَضْحَكَتْ ثمّ قالتْ كالمُغيثِ يُرَى ليثَ الشَّرَى وهوَ من عِجْلٍ إذا انتسبَا جاءتْ بأشجعِ مَن يُسمى وأسمحِ مَن أعطَى وأبلغِ مَنْ أملى ومَنْ كَتَبَا لوْ حَلّ خاطرُهُ في مُقْعَدٍ لمَشَى أو جاهلٍ لصَحا أو أخرَسٍ خَطَبَا إذا بَدا حَجَبَتْ عَيْنَيكَ هَيْبَتُهُ وليسَ يحجبُهُ سِترٌ إذا احتَجَبَا بَياضُ وَجْهٍ يُريكَ الشّمسَ حالكةً ودُرُّ لَفظٍ يُريكَ الدُّرَّ مَخْشَلَبَا وسَيفُ عَزْمٍ تَرُدّ السّيفَ هِبّتُهُ رَطْبَ الغِرارِ منَ التأمُورِ مُختَضِبَا عُمرُ العَدوّ إذا لاقاهُ في رَهَجٍ أقَلُّ مِنْ عُمْرِ ما يَحْوِي إذا وَهَبَا تَوَقَّهُ فَمَتى ما شِئْتَ تَبْلُوَهُ فكُنْ مُعادِيَهُ أوْ كُنْ له نَشَبَا تَحْلُو مَذاقَتُهُ حتى إذا غَضِبَا حالَتْ فلَوْ قطرَتْ في الماءِ ما شُرِبَا وتَغْبِطُ الأرْضُ منها حيثُ حَلّ بهِ وتَحْسُدُ الخيلُ منها أيَّها رَكِبَا ولا يَرُدّ بفيهِ كَفّ سائِلِهِ عن نَفسِهِ ويَرُدّ الجَحفَلَ اللّجِبَا وكُلّما لَقيَ الدّينارُ صاحِبَهُ في مُلكِه افترَقا من قبلِ يَصْطَحِبَا مالٌ كأنّ غُرابَ البَينِ يَرْقُبُهُ فكُلّما قيلَ هذا مُجْتَدٍ نَعَبَا بَحْرٌ عَجائِبُهُ لم تُبْقِ في سَمَرٍ ولا عَجائِبِ بحرٍ بَعدَها عَجَبَا لا يُقْنِعُ ابنَ عليٍّ نَيْلُ مَنزِلَةٍ يَشكُو مُحاوِلُها التّقصيرَ والتّعَبَا هَزّ اللّواءَ بَنو عِجْلٍ بهِ فَغَدا رأساً لهمْ وغَدا كُلٌّ لهُمْ ذَنَبَا التّارِكينَ منَ الأشياءِ أهْوَنَها والرّاكبينَ مِنَ الأشياءِ ما صَعُبَا مُبَرْقِعي خَيلِهمْ بالبِيضِ مُتّخذي هامِ الكُماةِ على أرماحِهِمْ عَذَبَا إنّ المَنيّةَ لَوْ لاقَتْهُمُ وَقَفَتْ خَرْقاءَ تَتّهِمُ الإقدامَ والهَرَبَا مَراتِبٌ صَعِدَتْ والفِكْرُ يَتْبَعُها فَجازَ وهْوَ على آثارِها الشُّهُبَا مَحامِدٌ نَزَفَتْ شِعْري ليَمْلأها فآلَ ما امتَلأتْ منْهُ ولا نَضَبَا مَكارِمٌ لكَ فُتَّ العالمينَ بِهَا مَنْ يَسْتَطيعُ لأمْرٍ فائِتٍ طَلَبَا لمّا أقَمْتَ بإنْطاكِيّةَ اخْتَلَفَتْ إليّ بالخَبرِ الرُّكْبانُ في حَلَبَا فَسِرْتُ نَحْوَكَ لا ألْوي على أحَدٍ أحُثّ راحلَتيَّ: الفَقْرَ والأدَبَا أذاقَني زَمَني بَلْوَى شَرِقْتُ بها لَوْ ذاقَها لَبَكَى ما عاشَ وانتَحَبَا وإنْ عَمَرْتُ جَعَلْتُ الحرْبَ والدةً والسّمْهَريَّ أخاً والمَشرَفيَّ أبَا بكلّ أشعثَ يَلقى الموْتَ مُبْتَسِماً حتى كأنّ لهُ في قَتْلِهِ أرَبَا قُحٍّ يَكادُ صَهيلُ الخَيلِ يَقذِفُهُ عن سرْجِهِ مَرَحاً بالعِزّ أو طَرَبَا فالمَوْتُ أعذَرُ لي والصّبرُ أجملُ بي والبَرُّ أوْسَعُ والدّنْيا لِمَنْ غَلَبَا
